// ─── Helpers ───
window.getQ = function(gid){ gid = parseInt(gid); return window.P2_DATA.find(q=>q.global_id===gid); };
window.getAsset = function(id){ return (window.ASSETS.assets||[]).find(a=>a.id===id); };
window.getStory = function(name){ return window.STORIES.find(s=>s.name===name); };
window.getQsByStory = function(name){ return window.P2_DATA.filter(q=>q.group===name); };
window.getQParam = function(){
  try{ return parseInt(new URLSearchParams(location.search).get('q')) || 1; }catch(e){ return 1; }
};
// NPC swap
window.NPC = { female:{name:'Lucy',emoji:'👩'}, male:{name:'Mark',emoji:'👨'} };
window.getGender = function(){ try{ return localStorage.getItem('beiya_gender')||'female'; }catch(e){ return 'female'; } };
window.applyNPC = function(){
  var n = window.NPC[window.getGender()] || window.NPC.female;
  document.querySelectorAll('[data-npc]').forEach(el=>el.textContent=n.name);
  document.querySelectorAll('[data-npc-emoji]').forEach(el=>el.textContent=n.emoji);
};
